    radial-gradient(circle at top left, hsl(18 82% 55% / 0.20), transparent 30%),
    radial-gradient(circle at right, hsl(208 88% 56% / 0.16), transparent 28%),
    linear-gradient(180deg, hsl(225 25% 12%) 0%, hsl(228 23% 8%) 100%);
  --text-color: hsl(40 25% 92%);
  --surface: hsl(225 18% 18% / 0.84);
  --surface-strong: hsl(226 18% 22% / 0.96);
  --surface-muted: hsl(226 18% 16% / 0.74);
  --border: hsl(215 35% 75% / 0.12);
  --accent: hsl(206 86% 61%);
  --accent-strong: hsl(19 88% 60%);
