   113	  const imageData = new ImageData(MANDELBROT_WIDTH, MANDELBROT_HEIGHT);
   114	
   115	  for (let y = 0; y < MANDELBROT_HEIGHT; y += 1) {
   116	    for (let x = 0; x < MANDELBROT_WIDTH; x += 1) {
   117	      const normalizedX = (x + 0.5) / MANDELBROT_WIDTH;
   118	      const normalizedY = (y + 0.5) / MANDELBROT_HEIGHT;
   119	      const cReal = viewport.minReal + getViewportWidth(viewport) * normalizedX;
   120	      const cImaginary = viewport.maxImaginary - getViewportHeight(viewport) * normalizedY;
   121	
   122	      let real = 0;
   123	      let imaginary = 0;
   124	      let escaped = false;
   125	      let iteration = 0;
   126	
   127	      for (; iteration < iterations; iteration += 1) {
   128	        const nextReal = real * real - imaginary * imaginary + cReal;
   129	        const nextImaginary = 2 * real * imaginary + cImaginary;
   130	        real = nextReal;
   131	        imaginary = nextImaginary;
   132	
   133	        if (real * real + imaginary * imaginary > 4) {
   134	          escaped = true;
   135	          break;
   136	        }
   137	      }
