   143	        imageData.data[pixelIndex + 1] = color.green;
   144	        imageData.data[pixelIndex + 2] = color.blue;
   145	        imageData.data[pixelIndex + 3] = 255;
   146	        continue;
   147	      }
   148	
   149	      const magnitudeSquared = real * real + imaginary * imaginary;
   150	      const smoothedIteration = iteration + 1 - Math.log2(Math.log2(Math.max(magnitudeSquared, 4)));
   151	      const normalized = Math.max(0, Math.min(1, smoothedIteration / iterations));
   152	      const color = getPaletteColor(palette, normalized);
   153	      imageData.data[pixelIndex] = clampByte(color.red);
   154	      imageData.data[pixelIndex + 1] = clampByte(color.green);
   155	      imageData.data[pixelIndex + 2] = clampByte(color.blue);
   156	      imageData.data[pixelIndex + 3] = 255;
   157	    }
   158	  }
