import { useEffect, useRef, useState } from "preact/hooks";

interface ResponsiveCanvasResolutionOptions {
  fallbackDisplayWidth: number;
  fallbackDisplayHeight: number;
  maxRenderWidth: number;
  maxRenderHeight: number;
  qualityScale: number;
  aspectRatio: number;
  sizingMode?: "contain" | "width-driven" | "height-driven";
}

interface CanvasResolution {
  displayWidth: number;
  displayHeight: number;
  renderWidth: number;
  renderHeight: number;
}

function getDevicePixelRatio(): number {
  if (typeof window === "undefined") {
    return 1;
  }

  return Math.max(window.devicePixelRatio || 1, 1);
}

function getBoundedRenderSize(
  displayWidth: number,
  displayHeight: number,
  devicePixelRatio: number,
  qualityScale: number,
  maxRenderWidth: number,
  maxRenderHeight: number,
): { renderWidth: number; renderHeight: number } {
  const rawRenderWidth = Math.max(1, Math.round(displayWidth * devicePixelRatio * qualityScale));
  const rawRenderHeight = Math.max(1, Math.round(displayHeight * devicePixelRatio * qualityScale));
  const scale = Math.min(
    1,
    maxRenderWidth / rawRenderWidth,
    maxRenderHeight / rawRenderHeight,
  );

  return {
    renderWidth: Math.max(1, Math.round(rawRenderWidth * scale)),
    renderHeight: Math.max(1, Math.round(rawRenderHeight * scale)),
  };
}

function resolveDisplaySize(
  measuredWidth: number,
  measuredHeight: number,
  options: ResponsiveCanvasResolutionOptions,
): { width: number; height: number } {
  const sizingMode = options.sizingMode ?? "contain";

  if (sizingMode === "contain") {
    const maxWidth = measuredWidth > 0 ? measuredWidth : options.fallbackDisplayWidth;
    const maxHeight = measuredHeight > 0 ? measuredHeight : options.fallbackDisplayHeight;

    if (maxWidth / maxHeight > options.aspectRatio) {
      const height = maxHeight;
      return {
        width: height * options.aspectRatio,
        height,
      };
    }

    const width = maxWidth;
    return {
      width,
      height: width / options.aspectRatio,
    };
  }

  if (sizingMode === "height-driven") {
    const height = measuredHeight > 0 ? measuredHeight : options.fallbackDisplayHeight;
    return {
      width: height * options.aspectRatio,
      height,
    };
  }

  const width = measuredWidth > 0 ? measuredWidth : options.fallbackDisplayWidth;
  return {
    width,
    height: width / options.aspectRatio,
  };
}

export function useResponsiveCanvasResolution(
  frameRef: preact.RefObject<HTMLElement>,
  options: ResponsiveCanvasResolutionOptions,
): CanvasResolution {
  const {
    aspectRatio,
    fallbackDisplayHeight,
    fallbackDisplayWidth,
    maxRenderHeight,
    maxRenderWidth,
    qualityScale,
    sizingMode,
  } = options;
  const [displaySize, setDisplaySize] = useState({
    width: resolveDisplaySize(fallbackDisplayWidth, fallbackDisplayHeight, options).width,
    height: resolveDisplaySize(fallbackDisplayWidth, fallbackDisplayHeight, options).height,
  });
  const devicePixelRatioRef = useRef(getDevicePixelRatio());

  useEffect(() => {
    function updateDevicePixelRatio(): void {
      devicePixelRatioRef.current = getDevicePixelRatio();
      const element = frameRef.current;
      if (!element) {
        return;
      }

      const rect = element.getBoundingClientRect();
      if (rect.width > 0 && rect.height > 0) {
        setDisplaySize(
          resolveDisplaySize(rect.width, rect.height, {
            aspectRatio,
            fallbackDisplayHeight,
            fallbackDisplayWidth,
            maxRenderHeight,
            maxRenderWidth,
            qualityScale,
            sizingMode,
          }),
        );
      }
    }

    window.addEventListener("resize", updateDevicePixelRatio);
    return () => window.removeEventListener("resize", updateDevicePixelRatio);
  }, [
    aspectRatio,
    fallbackDisplayHeight,
    fallbackDisplayWidth,
    frameRef,
    maxRenderHeight,
    maxRenderWidth,
    qualityScale,
    sizingMode,
  ]);

  useEffect(() => {
    const element = frameRef.current;
    if (!element) {
      return;
    }

    const observer = new ResizeObserver((entries) => {
      const entry = entries[0];
      if (!entry) {
        return;
      }

      const { width, height } = entry.contentRect;
      if (width <= 0 || height <= 0) {
        return;
      }

      setDisplaySize(
        resolveDisplaySize(width, height, {
          aspectRatio,
          fallbackDisplayHeight,
          fallbackDisplayWidth,
          maxRenderHeight,
          maxRenderWidth,
          qualityScale,
          sizingMode,
        }),
      );
    });

    observer.observe(element);
    return () => observer.disconnect();
  }, [
    aspectRatio,
    fallbackDisplayHeight,
    fallbackDisplayWidth,
    frameRef,
    maxRenderHeight,
    maxRenderWidth,
    qualityScale,
    sizingMode,
  ]);

  const { renderWidth, renderHeight } = getBoundedRenderSize(
    displaySize.width,
    displaySize.height,
    devicePixelRatioRef.current,
    qualityScale,
    maxRenderWidth,
    maxRenderHeight,
  );

  return {
    displayWidth: displaySize.width,
    displayHeight: displaySize.height,
    renderWidth,
    renderHeight,
  };
}

import { useEffect, useMemo, useRef, useState } from "preact/hooks";
import type { ComplexBounds, ComplexParameter, SomTrainingResult } from "@asimov/minimal-shared";
import crosshairUrl from "../assets/noun-crosshair-59595.svg";
import { getPaletteCssBackground, type FractalPaletteId } from "./fractal-palette.js";
import { CPU_EXPLORER_IMAGE_RENDERER } from "./explorer-cpu-renderer.js";
import type { ExplorerImageRenderer } from "./explorer-renderer.js";
import {
  drawMandelbrotAxesOverlay,
  drawOrbitOverlay,
  drawSomGridOverlay,
  getComplexBoundsHeight,
  getComplexBoundsWidth,
} from "./explorer-overlays.js";
import { useResponsiveCanvasResolution } from "./use-responsive-canvas-resolution.js";

const MANDELBROT_FALLBACK_WIDTH = 360;
const MANDELBROT_FALLBACK_HEIGHT = 240;
const MANDELBROT_MAX_RENDER_WIDTH = 2048;
const MANDELBROT_MAX_RENDER_HEIGHT = 1365;
const MANDELBROT_MAX_ITERATIONS = 96;
const CLICK_SELECTION_THRESHOLD = 5;
const DEFAULT_MANDELBROT_VIEWPORT: ComplexBounds = {
  minReal: -2.2,
  maxReal: 1.0,
  minImaginary: -1.0666666666666667,
  maxImaginary: 1.0666666666666667,
};
const MIN_VIEWPORT_SPAN = 0.02;
const ZOOM_IN_FACTOR = 0.85;
const ZOOM_OUT_FACTOR = 1 / ZOOM_IN_FACTOR;

interface DragState {
  pointerStartX: number;
  pointerStartY: number;
  viewportAtStart: ComplexBounds;
}

function formatComplex(parameter: ComplexParameter | null): string {
  if (!parameter) {
    return "n/a";
  }

  return `${parameter.real.toFixed(6)} ${parameter.imaginary >= 0 ? "+" : "-"} ${Math.abs(parameter.imaginary).toFixed(6)}i`;
}

function mapToRelativePosition(
  parameter: ComplexParameter,
  viewport: ComplexBounds,
): { left: string; top: string } {
  const normalizedX = (parameter.real - viewport.minReal) / getComplexBoundsWidth(viewport);
  const normalizedY = (viewport.maxImaginary - parameter.imaginary) / getComplexBoundsHeight(viewport);

  return {
    left: `${normalizedX * 100}%`,
    top: `${normalizedY * 100}%`,
  };
}

function mapPointToParameter(
  x: number,
  y: number,
  width: number,
  height: number,
  viewport: ComplexBounds,
): ComplexParameter {
  const normalizedX = x / width;
  const normalizedY = y / height;

  return {
    real: viewport.minReal + getComplexBoundsWidth(viewport) * normalizedX,
    imaginary: viewport.maxImaginary - getComplexBoundsHeight(viewport) * normalizedY,
  };
}

function zoomViewport(
  viewport: ComplexBounds,
  anchor: ComplexParameter,
  factor: number,
): ComplexBounds {
  const viewportWidth = getComplexBoundsWidth(viewport);
  const viewportHeight = getComplexBoundsHeight(viewport);
  const aspectRatio = viewportWidth / viewportHeight;
  const minimumWidth = MIN_VIEWPORT_SPAN * aspectRatio;
  const nextHeight = Math.max(viewportHeight * factor, MIN_VIEWPORT_SPAN);
  const nextWidth = Math.max(viewportWidth * factor, minimumWidth);
  const normalizedX = (anchor.real - viewport.minReal) / getComplexBoundsWidth(viewport);
  const normalizedY = (viewport.maxImaginary - anchor.imaginary) / getComplexBoundsHeight(viewport);

  return {
    minReal: anchor.real - nextWidth * normalizedX,
    maxReal: anchor.real + nextWidth * (1 - normalizedX),
    minImaginary: anchor.imaginary - nextHeight * (1 - normalizedY),
    maxImaginary: anchor.imaginary + nextHeight * normalizedY,
  };
}

function getCanvasPoint(canvas: HTMLCanvasElement, event: MouseEvent | WheelEvent): { x: number; y: number } {
  const rect = canvas.getBoundingClientRect();
  return {
    x: event.clientX - rect.left,
    y: event.clientY - rect.top,
  };
}

export function MandelbrotOverviewCanvas(props: {
  parameter: ComplexParameter | null;
  selectedParameter?: ComplexParameter | null;
  onHoverParameter: (parameter: ComplexParameter | null) => void;
  onSelectParameter?: (parameter: ComplexParameter) => void;
  result?: SomTrainingResult | null;
